#include &lt;stdint.h&gt;
#include &lt;stdbool.h&gt;

#define MAX_SENSORS 16U

typedef struct {
    uint32_t sensor_id;
    bool is_active;
} SensorNode;

// 1. Static Memory Pool allocated entirely at compile time.
// Sits safely in the .bss segment. Zero runtime allocation cost.
static SensorNode sensor_pool[MAX_SENSORS];

// 2. We maintain a static index or a bitmap to track used slots.
static uint8_t active_sensors = 0U;

// 3. The deterministic "allocation" function
SensorNode* allocate_sensor(void) {
    if (active_sensors >= MAX_SENSORS) {
        // Deterministic failure: We hit the hard mathematical limit.
        // The system gracefully refuses, rather than triggering a Heap OOM.
        return NULL;
    }

    SensorNode *new_sensor = &sensor_pool[active_sensors];
    active_sensors++;

    new_sensor->is_active = true;
    return new_sensor;
}

#include &lt;stdint.h&gt;

void calibrate_gyroscopes(void) {
    uint32_t gyro_offsets[3] = {0U, 0U, 0U};

    // Engineer adjusts bounds dynamically based on sensor count
    uint8_t sensor_count = 4U;

    // DANGER: An out-of-bounds write is structurally guaranteed here
    for (uint8_t i = 0U; i < sensor_count; i++) {
        gyro_offsets[i] = 100U;
    }
}
